// src/components/auth/Signup/Signup.jsx
import { useState } from 'react';
import { Link } from 'react-router-dom';
import StudentForm from './forms/StudentForm';
import InstructorForm from './forms/InstructorForm';
import './Signup.css';

export default function Signup() {
  const [role, setRole] = useState(''); // 'student' | 'instructor'

  return (
    <div className="relative flex min-h-screen w-full flex-col items-center justify-center bg-background-light dark:bg-background-dark overflow-x-hidden">
      <div className="layout-container flex h-full grow flex-col">
        <div className="px-4 flex flex-1 justify-center items-center py-5">
          <div className="layout-content-container flex flex-col max-w-[480px] w-full flex-1">

            {/* Logo & Title */}
            <div className="flex flex-col items-center gap-2 mb-6">
              <svg className="text-primary w-12 h-12" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="m8 3 4 8 5-5 5 15H2L8 3z" />
              </svg>
              <p className="text-2xl font-bold text-gray-900 dark:text-white">TunisiaED</p>
            </div>

            {/* Heading */}
            <div className="text-center mb-8">
              <h1 className="text-3xl font-bold text-gray-900 dark:text-white tracking-tighter">
                Create Your Account
              </h1>
              <p className="text-gray-500 dark:text-gray-400 mt-2">
                Start your journey with TunisiaED
              </p>
            </div>

            {/* Role Toggle */}
            <div className="relative grid grid-cols-2 gap-0 rounded-lg bg-gray-100 dark:bg-gray-800 p-1 mb-6">
              <div className={`absolute top-1 left-1 h-10 w-1/2 rounded-md bg-primary transition-transform duration-300 ${role === 'instructor' ? 'translate-x-full' : ''}`} id="slider" />
              <button
                onClick={() => setRole('student')}
                className={`relative z-10 h-10 text-sm font-semibold transition-colors ${role === 'student' ? 'text-white' : 'text-gray-600 dark:text-gray-400'}`}
              >
                Sign up as a Student
              </button>
              <button
                onClick={() => setRole('instructor')}
                className={`relative z-10 h-10 text-sm font-semibold transition-colors ${role === 'instructor' ? 'text-white' : 'text-gray-600 dark:text-gray-400'}`}
              >
                Sign up as an Instructor
              </button>
            </div>

            {/* Forms */}
            <div className="relative overflow-hidden">
              <div className={`transition-all duration-500 ease-in-out ${role === 'student' ? 'opacity-100 translate-x-0' : 'opacity-0 -translate-x-full'} absolute w-full`}>
                {role === 'student' && <StudentForm />}
              </div>
              <div className={`transition-all duration-500 ease-in-out ${role === 'instructor' ? 'opacity-100 translate-x-0' : 'opacity-0 translate-x-full'} ${role === 'student' ? 'absolute' : 'relative'} w-full`}>
                {role === 'instructor' && <InstructorForm />}
              </div>
            </div>

            {/* Already have account */}
            <p className="text-center text-sm text-gray-500 dark:text-gray-400 mt-8">
              Already have an account?{' '}
              <Link to="/login" className="text-primary font-medium underline hover:text-primary/80">
                Login
              </Link>
            </p>
          </div>
        </div>
      </div>
    </div>
  );
}
